  const SPEED_M_PER_S = HFC.createSpeedMPerSVector(builder, this.SPEED_M_PER_S);
  const MACH = HFC.createMachVector(builder, this.MACH);
  const DYNAMIC_PRESSURE_PA = HFC.createDynamicPressurePaVector(builder, this.DYNAMIC_PRESSURE_PA);
  const DENSITY_KG_PER_M3 = HFC.createDensityKgPerM3Vector(builder, this.DENSITY_KG_PER_M3);
  const TEMPERATURE_K = HFC.createTemperatureKVector(builder, this.TEMPERATURE_K);
  const PRESSURE_PA = HFC.createPressurePaVector(builder, this.PRESSURE_PA);
  const SPEED_OF_SOUND_M_PER_S = HFC.createSpeedOfSoundMPerSVector(builder, this.SPEED_OF_SOUND_M_PER_S);
