  const REYNOLDS_NUMBER = HFC.createReynoldsNumberVector(builder, this.REYNOLDS_NUMBER);
  const CONVECTIVE_HEAT_FLUX_W_PER_M2 = HFC.createConvectiveHeatFluxWPerM2Vector(builder, this.CONVECTIVE_HEAT_FLUX_W_PER_M2);
  const RADIATIVE_HEAT_FLUX_W_PER_M2 = HFC.createRadiativeHeatFluxWPerM2Vector(builder, this.RADIATIVE_HEAT_FLUX_W_PER_M2);
  const STAGNATION_HEAT_FLUX_W_PER_M2 = HFC.createStagnationHeatFluxWPerM2Vector(builder, this.STAGNATION_HEAT_FLUX_W_PER_M2);
  const LOAD_FACTOR_G = HFC.createLoadFactorGVector(builder, this.LOAD_FACTOR_G);
