  HFC.addSourceOem(builder, SOURCE_OEM);
  HFC.addSourceOcm(builder, SOURCE_OCM);
  HFC.addAtmosphere(builder, ATMOSPHERE);
  HFC.addAtmosphereProvider(builder, ATMOSPHERE_PROVIDER);
  HFC.addAtmosphereModelRevision(builder, ATMOSPHERE_MODEL_REVISION);
  HFC.addAtmosphereCoupling(builder, this.ATMOSPHERE_COUPLING);
  HFC.addAerothermalModel(builder, AEROTHERMAL_MODEL);
  HFC.addGasModel(builder, GAS_MODEL);
  HFC.addFlowRegime(builder, this.FLOW_REGIME);
  HFC.addStateVectorSize(builder, this.STATE_VECTOR_SIZE);
  HFC.addStateData(builder, STATE_DATA);
  HFC.addSampleEpochs(builder, SAMPLE_EPOCHS);
  HFC.addLatitudeDeg(builder, LATITUDE_DEG);
  HFC.addLongitudeDeg(builder, LONGITUDE_DEG);
  HFC.addAltitudeM(builder, ALTITUDE_M);
  HFC.addSpeedMPerS(builder, SPEED_M_PER_S);
  HFC.addMach(builder, MACH);
  HFC.addDynamicPressurePa(builder, DYNAMIC_PRESSURE_PA);
  HFC.addDensityKgPerM3(builder, DENSITY_KG_PER_M3);
  HFC.addTemperatureK(builder, TEMPERATURE_K);
  HFC.addPressurePa(builder, PRESSURE_PA);
  HFC.addSpeedOfSoundMPerS(builder, SPEED_OF_SOUND_M_PER_S);
  HFC.addKnudsenNumber(builder, KNUDSEN_NUMBER);
  HFC.addReynoldsNumber(builder, REYNOLDS_NUMBER);
  HFC.addConvectiveHeatFluxWPerM2(builder, CONVECTIVE_HEAT_FLUX_W_PER_M2);
  HFC.addRadiativeHeatFluxWPerM2(builder, RADIATIVE_HEAT_FLUX_W_PER_M2);
  HFC.addStagnationHeatFluxWPerM2(builder, STAGNATION_HEAT_FLUX_W_PER_M2);
  HFC.addLoadFactorG(builder, LOAD_FACTOR_G);
  HFC.addAngleOfAttackDeg(builder, ANGLE_OF_ATTACK_DEG);
  HFC.addSideslipDeg(builder, SIDESLIP_DEG);
  HFC.addBankAngleDeg(builder, BANK_ANGLE_DEG);
  HFC.addReferenceAreaM2(builder, this.REFERENCE_AREA_M2);
  HFC.addReferenceLengthM(builder, this.REFERENCE_LENGTH_M);
  HFC.addNoseRadiusM(builder, this.NOSE_RADIUS_M);
  HFC.addMassKg(builder, this.MASS_KG);
  HFC.addSurfaceTemperatureK(builder, this.SURFACE_TEMPERATURE_K);
  HFC.addAssumptions(builder, ASSUMPTIONS);
  HFC.addComment(builder, COMMENT);

  return HFC.endHFC(builder);
